import React from 'react';
import AlertEl,{AlertDescription, AlertIcon, AlertTitle} from './alert'
import type { IAlertProps } from "@lmb-it/kitsconcerto-types";


const Alert = ({status, variant, className, withIcon, children, title, description}:IAlertProps) => {

  return (
      <AlertEl status={status} className={className} variant={variant}>
          {withIcon && <AlertIcon status={status} />}
          {title && <AlertTitle>{title}</AlertTitle>}
          {description && <AlertDescription>{description}</AlertDescription>}
          {children}
      </AlertEl>
  );
};

export { AlertIcon, AlertTitle, AlertDescription };
export default Alert;
